templateSources.jira/common/templates/_jmx.tpl:
{{/*
Jmx config volume
*/}}
{{- define "common.jmx.config.volume" -}}
{{- if .Values.monitoring.exposeJmxMetrics }}
- name: jmx-config
  configMap:
    name: {{ include "common.names.fullname" . }}-jmx-config
{{- end }}
{{- end }}

{{/*
Jmx config volume mount
*/}}

{{- define "common.jmx.config.volumeMounts" -}}
{{- if .Values.monitoring.exposeJmxMetrics }}
- name: jmx-config
  mountPath: /opt/atlassian/jmx
{{- end }}
{{- end }}


{{/*
Jmx init container
*/}}
{{- define "common.jmx.initContainer" -}}
{{- if and .Values.monitoring.exposeJmxMetrics .Values.monitoring.fetchJmxExporterJar }}
- name: fetch-jmx-exporter
  image: {{ .Values.monitoring.jmxExporterImageRepo}}:{{ .Values.monitoring.jmxExporterImageTag}}
  command: ["cp"]
  args: ["{{ .Values.monitoring.jmxExporterInitContainer.jmxJarLocation | default "/opt/bitnami/jmx-exporter/jmx_prometheus_javaagent.jar" }}", "{{ .Values.volumes.sharedHome.mountPath }}"]
  {{- if .Values.monitoring.jmxExporterInitContainer.resources }}
  resources:
  {{- with .Values.monitoring.jmxExporterInitContainer.resources }}
  {{- toYaml . | nindent 4 }}
  {{- end }}
  {{- end }}
  {{- if .Values.openshift.runWithRestrictedSCC }}
  {{- else}}
  {{- if .Values.monitoring.jmxExporterInitContainer.runAsRoot }}
  securityContext:
    runAsUser: 0
  {{- else if .Values.monitoring.jmxExporterInitContainer.customSecurityContext }}
  securityContext:
  {{- with .Values.monitoring.jmxExporterInitContainer.customSecurityContext }}
  {{- toYaml .  | nindent 4 }}
  {{- end }}
  {{- end }}
  {{- end }}
  volumeMounts:
    - mountPath: {{ .Values.volumes.sharedHome.mountPath | quote }}
      name: shared-home
      {{- if .Values.volumes.sharedHome.subPath }}
      subPath: {{ .Values.volumes.sharedHome.subPath | quote }}
      {{- end }}
{{- end }}
{{- end }}

{{/*
Jmx port
*/}}
{{- define "common.jmx.port" -}}
{{- if .Values.monitoring.exposeJmxMetrics }}
- name: jmx
  containerPort: {{ .Values.monitoring.jmxExporterPort }}
  protocol: TCP
{{- end }}
{{- end }}

{{/*
Jmx javaagent
*/}}
{{- define "common.jmx.javaagent" -}}
{{- if .Values.monitoring.exposeJmxMetrics }}
-javaagent:{{ .Values.monitoring.jmxExporterCustomJarLocation | default (printf "%s/jmx_prometheus_javaagent.jar"  .Values.volumes.sharedHome.mountPath) }}={{ .Values.monitoring.jmxExporterPort}}:/opt/atlassian/jmx/jmx-config.yaml
{{- end }}
{{- end }}

{{/*
Jmx configuration yaml
*/}}
{{- define "common.jmx.config" -}}
{{ if .Values.monitoring.jmxExporterCustomConfig }}
{{- range $key, $value := .Values.monitoring.jmxExporterCustomConfig }}
{{ $key }}: |
{{ $value | indent 2 }}
{{- end }}
{{ else }}
jmx-config.yaml: |
  lowercaseOutputLabelNames: true
  lowercaseOutputName: true
  rules:
    - pattern: ".*"
{{- end }}
{{- end }}

templateSources.jira/common/templates/_labels.tpl:
{{/* vim: set filetype=mustache: */}}
{{/*
Common labels
*/}}
{{- define "common.labels.commonLabels" -}}
helm.sh/chart: {{ include "common.names.chart" . }}
{{ include "common.labels.selectorLabels" . }}
{{- if .Chart.AppVersion }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{ with .Values.additionalLabels }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
Selector labels
*/}}
{{- define "common.labels.selectorLabels" -}}
app.kubernetes.io/name: {{ include "common.names.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}

templateSources.jira/common/templates/_names.tpl:
{{/* vim: set filetype=mustache: */}}
{{/*
Expand the name of the chart.
*/}}
{{- define "common.names.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "common.names.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
We truncate at 63 chars because some Kubernetes name fields are limited to this (by the DNS naming spec).
If release name contains chart name it will be used as a full name.
*/}}
{{- define "common.names.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

templateSources.jira/templates/NOTES.txt:
Thank you for installing {{ title .Chart.Name }}.

Your release is named {{ .Release.Name }}, and resides in namespace {{ .Release.Namespace }}.

Please run sanity tests against the release to verify it's healthy:

  $ helm test {{ .Release.Name }} -n {{ .Release.Namespace }}

If the Kubernetes resources in the release are still starting up, then the tests may fail, so it
is advisable to wait for the tests to pass before continuing.

To see the custom values you used for this release:

  $ helm get values {{ .Release.Name }} -n {{ .Release.Namespace }}

{{- if eq (include "common.gateway.isConfigured" .) "true" -}}
{{ title .Chart.Name }} service URL: {{ include "common.gateway.origin" . }}{{ include "jira.path" . }}
{{- else }}
Get the {{ title .Chart.Name }} URL by running these commands in the same shell:
{{- if contains "NodePort" .Values.jira.service.type }}
  export NODE_PORT=$(kubectl get --namespace {{ .Release.Namespace }} -o jsonpath="{.spec.ports[0].nodePort}" services {{ .Release.Name }})
  export NODE_IP=$(kubectl get nodes --namespace {{ .Release.Namespace }} -o jsonpath="{.items[0].status.addresses[0].address}")
  echo http://$NODE_IP:$NODE_PORT
{{- else if contains "LoadBalancer" .Values.jira.service.type }}
  NOTE: It may take a few minutes for the LoadBalancer hostname to be available.
        You can watch the status of by running 'kubectl get svc --namespace {{ .Release.Namespace }} -w {{ .Release.Name }}'

  export SERVICE_HOSTNAME=$(kubectl get svc --namespace {{ .Release.Namespace }} {{ .Release.Name }} -o jsonpath='{.status.loadBalancer.ingress[0].hostname}')
  echo http://$SERVICE_HOSTNAME:{{ .Values.jira.service.port }}
{{- else if contains "ClusterIP" .Values.jira.service.type }}
  Step 1: Get the pod name
    $ export POD_NAME=$(kubectl get pods --namespace {{ .Release.Namespace }} -l "app.kubernetes.io/instance={{ .Release.Name }}" -o jsonpath="{.items[0].metadata.name}")
  Step 2 (Optional): Check if the pod name has been exported successfully and the pod status
    $ echo POD_NAME: $POD_NAME && echo POD_STATUS: $(kubectl get pod $POD_NAME -o jsonpath='{.status.phase}')
  Step 3: Wait for pods up and running, then forward pod port to localhost
    $ kubectl --namespace {{ .Release.Namespace }} port-forward $POD_NAME {{ .Values.jira.ports.http }}
  Step 4: Access {{ title .Chart.Name }} on localhost:
    http://localhost:{{ .Values.jira.ports.http }}
{{- end }}
{{- end }}
{{- if not ( or .Values.volumes.localHome.persistentVolumeClaim.create .Values.volumes.localHome.customVolume ) }}

#################################################################################
######      WARNING: Persistent volume is not used for Local Home!!!        #####
######            Data will be lost when the pod is terminated.             #####
#################################################################################
{{- end }}
{{- if not ( or .Values.volumes.sharedHome.persistentVolumeClaim.create .Values.volumes.sharedHome.customVolume ) }}

#################################################################################
######      WARNING: Persistent volume is not used for Shared Home!!!       #####
######            Data will be lost when the pod is terminated.             #####
#################################################################################
{{- end }}
{{- if ( or .Values.jira.securityContext.enabled .Values.jira.securityContext.gid ) }}

#################################################################################
######         DEPRECATION WARNING: jira.securityContext deprecation        #####
######       Update your values to the new jira.securityContext format      #####
#################################################################################
{{- end}}

For further documentation, see https://atlassian.github.io/data-center-helm-charts/

templateSources.jira/templates/_fluentd_templates.tpl:
{{- define "fluentd.container" -}}
{{ if .Values.fluentd.enabled }}
- name: fluentd
  image: {{ .Values.fluentd.imageRepo }}:{{ .Values.fluentd.imageTag }}
  command: ["sh", "-c", {{ include "fluentd.start.command" . | quote }}]
{{- if .Values.fluentd.resources }}
  resources:
  {{- with .Values.fluentd.resources }}
  {{- toYaml . | nindent 4 }}
  {{- end }}
{{- end }}
  volumeMounts:
    - name: fluentd-config
      mountPath: /fluentd/etc
      readOnly: true
{{- if .Values.fluentd.extraVolumes }}
  {{ toYaml .Values.fluentd.extraVolumes | nindent 4}}
{{- end }}
  env:
    - name: POD_NAME
      valueFrom:
        fieldRef:
          fieldPath: metadata.name
    - name: POD_NAMESPACE
      valueFrom:
        fieldRef:
          fieldPath: metadata.namespace
    - name: POD_IP
      valueFrom:
        fieldRef:
          fieldPath: status.podIP
    - name: HELM_RELEASE_NAME
      value: {{ include "common.names.fullname" . }}
{{ end }}
{{ end }}

{{- define "fluentd.config.volume" }}
{{ if .Values.fluentd.enabled }}
- name: fluentd-config
  configMap:
    name: {{ include "common.names.fullname" . }}-fluentd-config
{{ end }}
{{ end }}

templateSources.jira/templates/_helpers.tpl:
{{/* vim: set filetype=mustache: */}}

{{/* Define a sanitized list of additionalEnvironmentVariables */}}
{{- define "jira.sanitizedAdditionalEnvVars" -}}
{{- range .Values.jira.additionalEnvironmentVariables }}
- name: {{ .name }}
  value: {{ if regexMatch "(?i)(secret|token|password)" .name }}"Sanitized by Support Utility"{{ else}}{{ .value }}{{ end }}
{{- end }}
{{- end }}

{{- define "jira.sessionVars"}}
{{- if .Values.jira.session.timeout }}
- name: ATL_JIRA_SESSION_TIMEOUT
  value: {{ .Values.jira.session.timeout | int | quote }}
{{- end }}
{{- if .Values.jira.session.autologinCookieAge }}
- name: ATL_AUTOLOGIN_COOKIE_AGE
  value: {{ .Values.jira.session.autologinCookieAge | int| quote }}
{{- end }}
{{- end }}

{{- define "jira.tunnelVars"}}
{{- if .Values.jira.tunnel.additionalConnector.port }}
{{- with .Values.jira.tunnel.additionalConnector.port }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_PORT
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.connectionTimeout }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_CONNECTION_TIMEOUT
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.maxThreads }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_MAX_THREADS
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.minSpareThreads }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_MIN_SPARE_THREADS
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.enableLookups }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_ENABLE_LOOKUPS
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.acceptCount }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_ACCEPT_COUNT
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.secure }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_SECURE
  value: {{ . | quote }}
{{- end }}
{{- with .Values.jira.tunnel.additionalConnector.URIEncoding }}
- name: ATL_TOMCAT_ADDITIONAL_CONNECTOR_URI_ENCODING
  value: {{ . | quote }}
{{- end }}
{{- end }}
{{- end }}

{{/* Define a sanitized list of additionalJvmArgs */}}
{{- define "jira.sanitizedAdditionalJvmArgs" -}}
{{- range .Values.jira.additionalJvmArgs }}
 {{- $jvmArgs := regexSplit "=" . -1 }}
   {{- if regexMatch "(?i)(secret|token|password).*$" (first $jvmArgs) }}
-  {{ first $jvmArgs }}=Sanitized by Support Utility{{ else}}
-  {{ . }}
{{ end }}
{{- end }}
{{- end }}

{{/* Define sanitized Helm values */}}
{{- define "jira.sanitizedValues" -}}
{{- $sanitizedAdditionalEnvs := dict .Chart.Name (dict "additionalEnvironmentVariables" (include "jira.sanitizedAdditionalEnvVars" .)) }}
{{- $sanitizedAdditionalJvmArgs := dict .Chart.Name (dict "additionalJvmArgs" (include "jira.sanitizedAdditionalJvmArgs" .)) }}
{{- $mergedValues := merge $sanitizedAdditionalEnvs $sanitizedAdditionalJvmArgs .Values }}
{{- toYaml $mergedValues | replace " |2-" "" | replace " |-" "" |  replace "|2" "" | nindent 4 }}
{{- end }}

{{- define "jira.analyticsJson" -}}
{
  "imageTag": {{ if or (eq .Values.image.tag "") (eq .Values.image.tag nil) }}{{ .Chart.AppVersion | quote }}{{ else }}{{ regexSplit "-" .Values.image.tag -1 | first |  quote }}{{ end }},
  "replicas": {{ .Values.replicaCount }},
  "isJmxEnabled": {{ .Values.monitoring.exposeJmxMetrics }},
  "ingressType": {{ if not .Values.ingress.create }}"NONE"{{ else }}{{ if .Values.ingress.nginx }}"NGINX"{{ else }}"OTHER"{{ end }}{{ end }},
{{- $sanitizedMinorVersion := regexReplaceAll "[^0-9]" .Capabilities.KubeVersion.Minor "" }}
  "k8sVersion": "{{ .Capabilities.KubeVersion.Major }}.{{ $sanitizedMinorVersion }}",
  "isS3AvatarsEnabled": {{ if and .Values.jira.s3Storage.avatars.bucketName .Values.jira.s3Storage.avatars.bucketRegion }}true{{ else }}false{{ end }},
  "serviceType": {{ if regexMatch "^(ClusterIP|NodePort|LoadBalancer|ExternalName)$" .Values.jira.service.type }}{{ snakecase .Values.jira.service.type | upper | quote }}{{ else }}"UNKNOWN"{{ end }},
{{- if eq .Values.database.type nil }}
  "dbType": "UNKNOWN",
{{- else }}
{{- $databaseTypeMap := dict "postgres" "POSTGRES" "mssql" "MSSQL" "sqlserver" "SQLSERVER" "oracle" "ORACLE" "mysql" "MYSQL" }}
{{- $dbTypeInValues := .Values.database.type }}
{{- $dbType := "UNKNOWN" | quote }}
{{- range $key, $value := $databaseTypeMap }}
{{- if regexMatch (printf "(?i)%s" $key) $dbTypeInValues }}
  {{- $dbType = $value | quote }}
{{- end }}
{{- end }}
  "dbType": {{ $dbType }},
{{- end }}
  "isClusteringEnabled": {{ .Values.jira.clustering.enabled }},
  "isSharedHomePVCCreated": {{ .Values.volumes.sharedHome.persistentVolumeClaim.create }},
  "isServiceMonitorCreated": {{ .Values.monitoring.serviceMonitor.create }},
  "isGrafanaDashboardsCreated": {{ .Values.monitoring.grafana.createDashboards }},
  "isRunOnOpenshift": {{ .Capabilities.APIVersions.Has "route.openshift.io/v1/Route" }},
  "isRunWithRestrictedSCC": {{ .Values.openshift.runWithRestrictedSCC }},
  "isOpenshiftRouteCreated": {{ .Values.ingress.openShiftRoute}}
}
{{- end }}

{{/*
Create default value for the service path.
*/}}
{{- define "jira.path" -}}
{{- include "common.gateway.path" (dict
  "useGatewayMode" (include "common.gateway.useGatewayMode" .)
  "gatewayPath"   .Values.gateway.path
  "ingressPath"   .Values.ingress.path
  "contextPath"   .Values.jira.service.contextPath
) -}}
{{- end }}

{{/*
Alias for backward compatibility with ingress templates.
*/}}
{{- define "jira.ingressPath" -}}
{{- include "jira.path" . -}}
{{- end }}

{{/*
The name of the service account to be used.
If the name is defined in the chart values, then use that,
else if we're creating a new service account then use the name of the Helm release,
else just use the "default" service account.
*/}}
{{- define "jira.serviceAccountName" -}}
{{- if .Values.serviceAccount.name -}}
{{- .Values.serviceAccount.name -}}
{{- else -}}
{{- if .Values.serviceAccount.create -}}
{{- include "common.names.fullname" . -}}
{{- else -}}
default
{{- end -}}
{{- end -}}
{{- end }}

{{/*
Pod labels
*/}}
{{- define "jira.podLabels" -}}
{{ with .Values.podLabels }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
The command that should be run by the nfs-fixer init container to correct the permissions of the shared-home root directory.
*/}}
{{- define "jira.sharedHome.permissionFix.command" -}}
{{- $securityContext := .Values.jira.securityContext }}
{{- with .Values.volumes.sharedHome.nfsPermissionFixer }}
    {{- if .command }}
        {{ .command }}
    {{- else }}
        {{- if and $securityContext.gid $securityContext.enabled }}
            {{- printf "(chgrp %v %s; chmod g+w %s)" $securityContext.gid .mountPath .mountPath }}
        {{- else if $securityContext.fsGroup }}
            {{- printf "(chgrp %v %s; chmod g+w %s)" $securityContext.fsGroup .mountPath .mountPath }}
        {{- else }}
            {{- printf "(chgrp 2001 %s; chmod g+w %s)" .mountPath .mountPath }}
        {{- end }}
    {{- end }}
{{- end }}
{{- end }}

{{/*
The command that should be run to start the fluentd service
*/}}
{{- define "fluentd.start.command" -}}
{{- if .Values.fluentd.command }}
{{ .Values.fluentd.command }}
{{- else }}
{{- print "exec fluentd -c /fluentd/etc/fluent.conf -v" }}
{{- end }}
{{- end }}

{{- define "jira.image" -}}
{{- if .Values.image.registry -}}
{{ .Values.image.registry}}/{{ .Values.image.repository }}:{{ .Values.image.tag | default .Chart.AppVersion }}
{{- else -}}
{{ .Values.image.repository }}:{{ .Values.image.tag | default .Chart.AppVersion }}
{{- end }}
{{- end }}

{{/*
Defines the volume mounts used by the Jira container.
Note that the local-home volume is mounted twice, once for the local-home directory itself, and again
on Tomcat's logs directory. THis ensures that Tomcat+Jira logs get captured in the same volume.
*/}}
{{ define "jira.volumeMounts" }}
- name: local-home
  mountPath: {{ .Values.volumes.localHome.mountPath | quote }}
  {{- if .Values.volumes.localHome.subPath }}
  subPath: {{ .Values.volumes.localHome.subPath | quote }}
  {{- end }}
- name: local-home
  mountPath: {{ .Values.jira.accessLog.mountPath | quote }}
  subPath: {{ .Values.jira.accessLog.localHomeSubPath | quote }}
- name: shared-home
  mountPath: {{ .Values.volumes.sharedHome.mountPath | quote }}
  {{- if .Values.volumes.sharedHome.subPath }}
  subPath: {{ .Values.volumes.sharedHome.subPath | quote }}
  {{- end }}
{{- if or .Values.jira.tomcatConfig.generateByHelm .Values.openshift.runWithRestrictedSCC }}
- name: server-xml
  mountPath: /opt/atlassian/jira/conf/server.xml
  subPath: server.xml
- name: temp
  mountPath: /opt/atlassian/jira/temp
- name: work
  mountPath: /opt/atlassian/jira/work
{{- end }}
{{- if or .Values.jira.seraphConfig.generateByHelm .Values.openshift.runWithRestrictedSCC }}
- name: seraph-config-xml
  mountPath: /opt/atlassian/jira/atlassian-jira/WEB-INF/classes/seraph-config.xml
  subPath: seraph-config.xml
{{- end }}
{{- if or .Values.jira.additionalCertificates.secretName .Values.jira.additionalCertificates.secretList }}
- name: keystore
  mountPath: /var/ssl
{{- end }}
{{- if or .Values.atlassianAnalyticsAndSupport.analytics.enabled .Values.atlassianAnalyticsAndSupport.helmValues.enabled }}
- name: helm-values
  mountPath: /opt/atlassian/helm
{{- end }}
{{- end }}

{{/*
Define pod annotations here to allow template overrides when used as a sub chart
*/}}
{{- define "jira.podAnnotations" -}}
{{- range $key, $value := .Values.podAnnotations }}
{{ $key }}: {{ tpl $value $ | quote }}
{{- end }}
{{- end }}

{{/*
Define additional init containers here to allow template overrides when used as a sub chart
*/}}
{{- define "jira.additionalInitContainers" -}}
{{- with .Values.additionalInitContainers }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
Define additional containers here to allow template overrides when used as a sub chart
*/}}
{{- define "jira.additionalContainers" -}}
{{- with .Values.additionalContainers }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
Define additional ports here instead of in values.yaml to allow template overrides
*/}}
{{- define "jira.additionalPorts" -}}
{{- with .Values.jira.additionalPorts }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
Define additional volume mounts here to allow template overrides when used as a sub chart
*/}}
{{- define "jira.additionalVolumeMounts" -}}
{{- with .Values.jira.additionalVolumeMounts }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
Define additional environment variables here to allow template overrides when used as a sub chart
*/}}
{{- define "jira.additionalEnvironmentVariables" -}}
{{- with .Values.jira.additionalEnvironmentVariables }}
{{- toYaml . }}
{{- end }}
{{- end }}

{{/*
Renders ADDITIONAL_JIRA_CONFIG_* environment variables from additionalConfigProperties values
*/}}
{{- define "jira.additionalConfigProperties" -}}
{{- range $index, $prop := .Values.jira.additionalConfigProperties }}
- name: {{ printf "ADDITIONAL_JIRA_CONFIG_HELM_%03d" $index }}
  value: {{ $prop | quote }}
{{- end }}
{{- range $index, $prop := .Values.jira.additionalConfigPropertiesExpandEnv }}
- name: {{ printf "ADDITIONAL_JIRA_CONFIG_HELM_%03d__EXPAND_ENV" $index }}
  value: {{ $prop | quote }}
{{- end }}
{{- end }}

{{/*
For each additional library declared, generate a volume mount that injects that library into the Jira lib directory
*/}}
{{- define "jira.additionalLibraries" -}}
{{- range .Values.jira.additionalLibraries }}
- name: {{ .volumeName }}
  mountPath: "/opt/atlassian/jira/lib/{{ .fileName }}"
  {{- if .subDirectory }}
  subPath: {{ printf "%s/%s" .subDirectory .fileName | quote }}
  {{- else }}
  subPath: {{ .fileName | quote }}
  {{- end }}
{{- end }}
{{- end }}

{{/*
For each additional plugin declared, generate a volume mount that injects that library into the Jira plugins directory
*/}}
{{- define "jira.additionalBundledPlugins" -}}
{{- range .Values.jira.additionalBundledPlugins }}
- name: {{ .volumeName }}
  mountPath: "/opt/atlassian/jira/atlassian-jira/WEB-INF/atlassian-bundled-plugins/{{ .fileName }}"
  {{- if .subDirectory }}
  subPath: {{ printf "%s/%s" .subDirectory .fileName | quote }}
  {{- else }}
  subPath: {{ .fileName | quote }}
  {{- end }}
{{- end }}
{{- end }}

{{- define "jira.volumes" -}}
{{ if not .Values.volumes.localHome.persistentVolumeClaim.create }}
{{ include "jira.volumes.localHome" . }}
{{- end }}
{{ include "jira.volumes.sharedHome" . }}
{{- with .Values.volumes.additional }}
{{- toYaml . | nindent 0 }}
{{- end }}
{{- if or .Values.jira.tomcatConfig.generateByHelm .Values.openshift.runWithRestrictedSCC }}
- name: server-xml
  configMap:
    name: {{ include "common.names.fullname" . }}-server-config
    items:
      - key: server.xml
        path: server.xml
- name: temp
  emptyDir: {}
- name: work
  emptyDir: {}
{{- end }}
{{- if or .Values.jira.seraphConfig.generateByHelm .Values.openshift.runWithRestrictedSCC }}
- name: seraph-config-xml
  configMap:
    name: {{ include "common.names.fullname" . }}-server-config
    items:
      - key: seraph-config.xml
        path: seraph-config.xml
{{- end }}
{{- if or .Values.jira.additionalCertificates.secretName .Values.jira.additionalCertificates.secretList }}
- name: keystore
  emptyDir: {}
{{- if .Values.jira.additionalCertificates.secretName }}
- name: certs
  secret:
    secretName: {{ .Values.jira.additionalCertificates.secretName }}
{{- else }}
{{- range .Values.jira.additionalCertificates.secretList }}
- name: {{ .name }}
