                name: {{ include "common.names.fullname" $ }}
                port:
                  number: {{ $.Values.jira.service.port }}
         {{- range $path := .Values.ingress.additionalPaths }}
          - path: {{ $path.path }}
            pathType: {{ $path.pathType | default "Prefix" }}
