templateSources.jira/templates/statefulset.yaml:
{{- include "common.gateway.validateConfig" . -}}
apiVersion: apps/v1
kind: StatefulSet
metadata:
  name: {{ include "common.names.fullname" . }}
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
  annotations:
    {{- with .Values.jira.additionalAnnotations }}
    {{- toYaml . | nindent 4 }}
    {{- end }}
spec:
  {{- if .Values.updateStrategy }}
  {{- with .Values.updateStrategy }}
  updateStrategy:
  {{- toYaml . | nindent 4 }}
  {{- end }}
  {{- end }}
  {{ if .Values.ordinals.enabled }}
  ordinals:
    start: {{ .Values.ordinals.start }}
  {{ end }}
  replicas: {{ .Values.replicaCount }}
  serviceName: {{ include "common.names.fullname" . }}
  selector:
    matchLabels:
      {{- include "common.labels.selectorLabels" . | nindent 6 }}
  template:
    metadata:
      annotations:
        checksum/config-jvm: {{ include (print $.Template.BasePath "/config-jvm.yaml") . | sha256sum }}
        {{- if .Values.additionalConfigMaps }}
        checksum/config-additional: {{ include (print $.Template.BasePath "/configmap-additional-config.yaml") . | sha256sum }}
        {{- end }}
        {{- if .Values.fluentd.enabled }}
        checksum/config-fluentd: {{ include (print $.Template.BasePath "/configmap-fluentd.yaml") . | sha256sum }}
        {{- end }}
        {{- include "jira.podAnnotations" . | nindent 8 }}
      labels:
        {{- include "common.labels.commonLabels" . | nindent 8 }}
        {{- include "jira.podLabels" . | nindent 8 }}
    spec:
      {{- with .Values.hostNamespaces }}
      {{- toYaml . | nindent 6 }}
      {{- end }}
      serviceAccountName: {{ include "jira.serviceAccountName" . }}
      terminationGracePeriodSeconds: {{ .Values.jira.shutdown.terminationGracePeriodSeconds }}
      hostAliases:
      {{- include "jira.additionalHosts" . | nindent 8 }}
      {{- if .Values.openshift.runWithRestrictedSCC }}
      {{- else }}
      {{- if .Values.jira.securityContextEnabled }}
      {{- with .Values.jira.securityContext }}
      securityContext:
        {{ toYaml . | nindent 8 }}
        {{- if not .fsGroup }}
        fsGroup: 2001
        {{- end }}
      {{- end }}
      {{- end }}
      {{- end }}
      initContainers:
        {{- if .Values.opensearch.enabled }}
        - name: opensearch-check
          image: {{ include "jira.image" . | quote }}
          command: ['sh', '-c']
          args:
          - |
            timeout=300
            end=$(($(date +%s) + timeout))
            while [ $(date +%s) -lt $end ]; do
              if curl -s -o /dev/null -w "%{http_code}" http://opensearch-cluster-master:9200 | grep -qE '^(200|401|403)$'; then
                echo "OpenSearch is ready"
                exit 0
              fi
              echo "OpenSearch server not ready or not reachable. Waiting..."
              sleep 5
            done
            echo "OpenSearch did not become ready in ${timeout} seconds. Exiting"
            exit 1
        {{- end }}
        {{- include "jira.additionalInitContainers" . | nindent 8 }}
        {{- if and .Values.volumes.sharedHome.nfsPermissionFixer.enabled (not .Values.openshift.runWithRestrictedSCC) }}
        - name: nfs-permission-fixer
          image: {{ .Values.volumes.sharedHome.nfsPermissionFixer.imageRepo }}:{{ .Values.volumes.sharedHome.nfsPermissionFixer.imageTag }}
          imagePullPolicy: IfNotPresent
          {{- if .Values.volumes.sharedHome.nfsPermissionFixer.resources }}
          resources:
          {{- with .Values.volumes.sharedHome.nfsPermissionFixer.resources }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
          {{- end }}
          securityContext:
            runAsUser: 0 # make sure we run as root so we get the ability to change the volume permissions
          volumeMounts:
            - name: shared-home
              mountPath: {{ .Values.volumes.sharedHome.nfsPermissionFixer.mountPath | quote }}
              {{- if .Values.volumes.sharedHome.subPath }}
              subPath: {{ .Values.volumes.sharedHome.subPath | quote }}
              {{- end }}
          command: ["sh", "-c", {{ include "jira.sharedHome.permissionFix.command" . | quote }}]
        {{- end }}
        {{- include "common.jmx.initContainer" . | nindent 8 }}
        {{- if or .Values.jira.additionalCertificates.secretName .Values.jira.additionalCertificates.secretList }}
        - name: import-certs
          image: {{ include "jira.image" . | quote }}
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          volumeMounts:
            - name: keystore
              mountPath: /var/ssl
          {{- if.Values.jira.additionalCertificates.secretName }}
            - name: certs
              mountPath: /tmp/crt
          {{- else }}
          {{- range .Values.jira.additionalCertificates.secretList }}
            {{- $secretName := .name }}
            {{- range .keys }}
            - name: {{ $secretName }}
              mountPath: /tmp/crt/{{$secretName}}-{{ . }}
              subPath: {{ . }}
            {{- end }}
          {{- end }}
          {{- end }}
          command: ["/bin/bash"]
          args: ["-c", {{ include "jira.addCrtToKeystoreCmd" . }}]
          resources:
          {{- with .Values.jira.additionalCertificates.initContainer.resources }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
          securityContext:
          {{- with .Values.jira.additionalCertificates.initContainer.securityContext }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
        {{- end }}
      containers:
        - name: {{ if .Values.jira.useHelmReleaseNameAsContainerName}}{{ include "common.names.fullname" . }}{{ else }}{{ .Chart.Name }}{{ end }}
          image: {{ include "jira.image" . | quote }}
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          env:
            {{- include "jira.sessionVars" . | nindent 12 }}
            {{- include "jira.tunnelVars" . | nindent 12 }}
            {{ if eq (include "common.gateway.https" .) "true" }}
            - name: ATL_TOMCAT_SCHEME
              value: "https"
            - name: ATL_TOMCAT_SECURE
              value: "true"
            {{ end }}
            {{ if .Values.jira.service.contextPath }}
            - name: ATL_TOMCAT_CONTEXTPATH
              value: {{ .Values.jira.service.contextPath | quote }}
            {{ end }}
            - name: ATL_TOMCAT_PORT
              value: {{ .Values.jira.ports.http | quote }}
            {{ if eq (include "common.gateway.isConfigured" .) "true" }}
            - name: ATL_PROXY_NAME
              value: {{ include "common.gateway.hostname" . | quote }}
            - name: ATL_PROXY_PORT
              value: {{ include "common.gateway.externalPort" . | quote }}
            {{ end }}
            {{- include "jira.s3StorageEnvVars" . | nindent 12 }}
            {{- include "jira.databaseEnvVars" . | nindent 12 }}
            {{- include "jira.clusteringEnvVars" . | nindent 12 }}
            - name: SET_PERMISSIONS
              value: {{ .Values.jira.setPermissions | quote }}
            - name: JIRA_SHARED_HOME
              value: {{ .Values.volumes.sharedHome.mountPath | quote }}
            - name: JVM_SUPPORT_RECOMMENDED_ARGS
              valueFrom:
                configMapKeyRef:
                  key: additional_jvm_args
                  name: {{ include "common.names.fullname" . }}-jvm-config
            - name: JVM_MINIMUM_MEMORY
              valueFrom:
                configMapKeyRef:
                  key: min_heap
                  name: {{ include "common.names.fullname" . }}-jvm-config
            - name: JVM_MAXIMUM_MEMORY
              valueFrom:
                configMapKeyRef:
                  key: max_heap
                  name: {{ include "common.names.fullname" . }}-jvm-config
            - name: JVM_RESERVED_CODE_CACHE_SIZE
              valueFrom:
                configMapKeyRef:
                  key: reserved_code_cache
                  name: {{ include "common.names.fullname" . }}-jvm-config
            {{- if .Values.monitoring.exposeJmxMetrics }}
            - name: CATALINA_OPTS
              value: {{ include "common.jmx.javaagent" . | replace "\n" "" | quote }}
            {{- end }}
            {{- include "opensearch.env.vars" . | nindent 12 }}
            {{- include "jira.additionalConfigProperties" . | nindent 12 }}
            {{- include "jira.additionalEnvironmentVariables" . | nindent 12 }}
          ports:
            - name: http
              containerPort: {{ .Values.jira.ports.http }}
              protocol: TCP
            - name: ehcache
              containerPort: {{ .Values.jira.ports.ehcache }}
              protocol: TCP
            - name: ehcacheobject
              containerPort: {{ .Values.jira.ports.ehcacheobject }}
              protocol: TCP
            {{- include "jira.additionalPorts" . | nindent 12 }}
            {{- include "common.jmx.port" . | nindent 12 }}
          {{- if .Values.jira.readinessProbe.enabled }}
          readinessProbe:
            {{- if .Values.jira.readinessProbe.customProbe}}
            {{- with .Values.jira.readinessProbe.customProbe }}
            {{- toYaml . | nindent 12 }}
            {{- end }}
            {{- else }}
            httpGet:
              port: {{ .Values.jira.ports.http }}
              path: {{ .Values.jira.service.contextPath }}/status
            initialDelaySeconds: {{ .Values.jira.readinessProbe.initialDelaySeconds }}
            periodSeconds: {{ .Values.jira.readinessProbe.periodSeconds }}
            timeoutSeconds: {{ .Values.jira.readinessProbe.timeoutSeconds }}
            failureThreshold: {{ .Values.jira.readinessProbe.failureThreshold }}
            {{- end }}
          {{- end }}
          {{- if .Values.jira.startupProbe.enabled }}
          startupProbe:
            tcpSocket:
              port: {{ .Values.jira.ports.http }}
            initialDelaySeconds: {{ .Values.jira.startupProbe.initialDelaySeconds }}
            periodSeconds: {{ .Values.jira.startupProbe.periodSeconds }}
            failureThreshold: {{ .Values.jira.startupProbe.failureThreshold }}
          {{- end }}
          {{- if .Values.jira.livenessProbe.enabled }}
          livenessProbe:
            {{- if .Values.jira.livenessProbe.customProbe}}
            {{- with .Values.jira.livenessProbe.customProbe }}
            {{- toYaml . | nindent 12 }}
            {{- end }}
            {{- else }}
            tcpSocket:
              port: {{ .Values.jira.ports.http }}
            initialDelaySeconds: {{ .Values.jira.livenessProbe.initialDelaySeconds }}
            periodSeconds: {{ .Values.jira.livenessProbe.periodSeconds }}
            timeoutSeconds: {{ .Values.jira.livenessProbe.timeoutSeconds }}
            failureThreshold: {{ .Values.jira.livenessProbe.failureThreshold }}
          {{- end }}
          {{- end }}
          {{- with .Values.jira.containerSecurityContext}}
          securityContext:
          {{- toYaml . | nindent 12}}
          {{- end}}
          {{- with .Values.jira.resources.container }}
          resources:
            {{- toYaml . | nindent 12 }}
          {{- end }}
          volumeMounts:
            {{- include "jira.volumeMounts" . | nindent 12 }}
            {{- include "common.jmx.config.volumeMounts" . | nindent 12 }}
            {{- include "jira.additionalVolumeMounts" . | nindent 12 }}
            {{- include "jira.additionalLibraries" . | nindent 12 }}
            {{- include "jira.additionalBundledPlugins" . | nindent 12 }}
            {{- range $i, $n := .Values.additionalFiles }}
            - name: {{ .name }}-{{$i}}
              mountPath: {{ .mountPath }}/{{ .key }}
              subPath: {{ .key }}
            {{ end }}
            {{- range $i, $n := .Values.additionalConfigMaps }}
            {{- range .keys }}
            - name: {{ .fileName | replace "_" "-" | replace "." "-" }}
              mountPath: {{ .mountPath }}/{{ .fileName }}
              subPath: {{ .fileName }}
            {{ end }}
            {{- end }}
          lifecycle:
          {{- if .Values.jira.postStart.command }}
            postStart:
              exec:
                command: ["/bin/sh", "-c", {{- .Values.jira.postStart.command | quote }}]
          {{- end }}
            preStop:
              exec:
                command: ["sh", "-c", {{ .Values.jira.shutdown.command | quote }}]
        {{- include "fluentd.container" . | nindent 8 }}
        {{- include "jira.additionalContainers" . | nindent 8 }}
      {{- with .Values.nodeSelector }}
      nodeSelector:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.affinity }}
      affinity:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.tolerations }}
      tolerations:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.jira.topologySpreadConstraints }}
      topologySpreadConstraints:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- if .Values.priorityClassName }}
      priorityClassName: {{ .Values.priorityClassName }}
      {{- end }}
      {{- if .Values.schedulerName }}
      schedulerName: {{ .Values.schedulerName  | quote }}
      {{- end }}
      volumes:
        {{- range $i, $n := .Values.additionalFiles }}
        - name: {{ .name }}-{{$i}}
          {{ .type }}:
            {{ if hasPrefix .type "secret" }}{{ .type}}Name{{ else }}name{{ end }}: {{ .name }}
            items:
              - key: {{ .key }}
                path: {{ .key }}
        {{ end }}
        {{- range $i, $key := .Values.additionalConfigMaps }}
        {{- with $ }}
        {{- range $key.keys }}
        - name: {{ .fileName | replace "_" "-" | replace "." "-" }}
          configMap:
            name: {{ include "common.names.fullname" $ }}-{{ $key.name }}
            {{- if .defaultMode }}
            defaultMode: {{ .defaultMode }}
            {{- end }}
            items:
              - key: {{ .fileName }}
                path: {{ .fileName }}
            {{- end }}
        {{ end }}
        {{- end }}
        {{ include "jira.volumes" . | nindent 8 }}
        {{ include "fluentd.config.volume" . | nindent 8 }}
        {{ include "common.jmx.config.volume" . | nindent 8 }}
  {{ include "jira.volumeClaimTemplates" . | nindent 2 }}

templateSources.jira/templates/tests/test-application-st:
apiVersion: v1
kind: Pod
metadata:
  name: "{{ include "common.names.fullname" . }}-application-status-test"
  annotations:
    "helm.sh/hook": test
    "helm.sh/hook-delete-policy": "before-hook-creation,hook-succeeded"
    {{- if not .Values.testPods.annotations }}
    {{- include "jira.podAnnotations" . | nindent 4 }}
    {{- else }}
    {{- range $key, $value := .Values.testPods.annotations }}
    {{ $key | quote }}: {{ tpl $value $ | quote }}
    {{- end }}
    {{- end }}
  labels:
    {{- if not .Values.testPods.labels }}
    {{- include "common.labels.commonLabels" . | nindent 4 }}
    {{- else }}
    {{- range $key, $value := .Values.testPods.labels }}
    {{ $key | quote }}: {{ tpl $value $ | quote }}
    {{- end }}
    {{- end }}
spec:
  containers:
    - name: test
      image: {{ .Values.testPods.image.statusTestContainer }}
      imagePullPolicy: IfNotPresent
      env:
        - name: STATUS_URL
          value: "http://{{ include "common.names.fullname" . }}:{{ .Values.jira.service.port }}/status"
      command:
        - /bin/sh
        - -ec
        - |
          apk add -q jq curl
          STATUS=$(curl -s "$STATUS_URL")
          echo "Verifying application state is RUNNING or FIRST_RUN: $STATUS"
          echo $STATUS | jq -e '.state|test("RUNNING|FIRST_RUN")'
      {{- with .Values.testPods.resources }}
      resources:
      {{- toYaml . | nindent 8 }}
      {{- end }}
  restartPolicy: Never
  {{- with .Values.testPods.nodeSelector }}
  nodeSelector:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- with .Values.testPods.affinity }}
  affinity:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- with .Values.testPods.tolerations }}
  tolerations:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- if .Values.testPods.schedulerName }}
  schedulerName: {{ .Values.testPods.schedulerName  | quote }}
  {{- end }}

templateSources.jira/templates/tests/test-database-conne:
{{ if .Values.database.credentials.secretName }}
apiVersion: v1
kind: Pod
metadata:
  name: "{{ include "common.names.fullname" . }}-db-connectivity-test"
  annotations:
    "helm.sh/hook": test
    "helm.sh/hook-delete-policy": "before-hook-creation,hook-succeeded"
    {{- if not .Values.testPods.annotations }}
    {{- include "jira.podAnnotations" . | nindent 4 }}
    {{- else }}
    {{- range $key, $value := .Values.testPods.annotations }}
    {{ $key | quote }}: {{ tpl $value $ | quote }}
    {{- end }}
    {{- end }}
  labels:
    {{- if not .Values.testPods.labels }}
    {{- include "common.labels.commonLabels" . | nindent 4 }}
    {{- else }}
    {{- range $key, $value := .Values.testPods.labels }}
    {{ $key | quote }}: {{ tpl $value $ | quote }}
    {{- end }}
    {{- end }}
spec:
  serviceAccountName: {{ include "jira.serviceAccountName" . }}
  containers:
    - name: test
      image: {{ include "jira.image" . | quote }}
      imagePullPolicy: IfNotPresent
      env:
        - name: JDBC_DRIVER
          value: {{ .Values.database.driver | quote }}
        - name: JDBC_URL
          value: {{ .Values.database.url | quote }}
        - name: JDBC_USER
          valueFrom:
            secretKeyRef:
              name: {{ .Values.database.credentials.secretName }}
              key: {{ .Values.database.credentials.usernameSecretKey }}
        - name: JDBC_PASSWORD
          valueFrom:
            secretKeyRef:
              name: {{ .Values.database.credentials.secretName }}
              key: {{ .Values.database.credentials.passwordSecretKey }}
        - name: CLASSPATH
          value: "/opt/atlassian/jira/lib/*"
      command:
        - /bin/bash
        - -ec
        - |
          cat <<EOF | jshell - > output.txt
          var jdbcDriver = System.getenv("JDBC_DRIVER");
          var jdbcUrl = System.getenv("JDBC_URL");
          var jdbcUsername = System.getenv("JDBC_USER");
          var jdbcPassword = System.getenv("JDBC_PASSWORD");

          System.out.println("Loading driver " + jdbcDriver);
          Class.forName(jdbcDriver);

          System.out.println("Establishing connection to " + jdbcUrl);
          try (var c = java.sql.DriverManager.getConnection(jdbcUrl, jdbcUsername, jdbcPassword)) {
             System.out.println("Connection established OK, " + c.getClass());
          }
          EOF
          cat output.txt
          grep -q "Connection established OK" output.txt
      {{- with .Values.testPods.resources }}
      resources:
      {{- toYaml . | nindent 8 }}
      {{- end }}
  restartPolicy: Never
  {{- with .Values.testPods.nodeSelector }}
  nodeSelector:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- with .Values.testPods.affinity }}
  affinity:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- with .Values.testPods.tolerations }}
  tolerations:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- if .Values.testPods.schedulerName }}
  schedulerName: {{ .Values.testPods.schedulerName  | quote }}
  {{- end }}
{{ end }}

templateSources.jira/templates/tests/test-shared-home-pe:
apiVersion: v1
kind: Pod
metadata:
  name: "{{ include "common.names.fullname" . }}-shared-home-permissions-test"
  annotations:
    "helm.sh/hook": test
    "helm.sh/hook-delete-policy": "before-hook-creation,hook-succeeded"
    {{- if not .Values.testPods.annotations }}
    {{- include "jira.podAnnotations" . | nindent 4 }}
    {{- else }}
    {{- range $key, $value := .Values.testPods.annotations }}
    {{ $key | quote }}: {{ tpl $value $ | quote }}
    {{- end }}
    {{- end }}
  labels:
    {{- if not .Values.testPods.labels }}
    {{- include "common.labels.commonLabels" . | nindent 4 }}
    {{- else }}
    {{- range $key, $value := .Values.testPods.labels }}
    {{ $key | quote }}: {{ tpl $value $ | quote }}
    {{- end }}
    {{- end }}
spec:
  containers:
    - name: test
      image: {{ .Values.testPods.image.permissionsTestContainer }}
      imagePullPolicy: IfNotPresent
      securityContext:
        # We assume that the UID and GID used by the product images are the same, which in practice they are
        {{- with .Values.jira.securityContext }}
        {{- if and .enabled .gid }}
        runAsUser: {{ .gid }}
        runAsGroup: {{ .gid }}
        {{- else if .fsGroup }}
        runAsUser: {{ .fsGroup }}
        runAsGroup: {{ .fsGroup }}
        {{- else }}
        runAsUser: {{ 2001 }}
        runAsGroup: {{ 2001 }}
        {{- end }}
        {{- end }}
      volumeMounts:
        - name: shared-home
          mountPath: /shared-home
          {{- if .Values.volumes.sharedHome.subPath }}
          subPath: {{ .Values.volumes.sharedHome.subPath | quote }}
          {{- end }}
      command:
        - /bin/sh
        - -ec
        - |
          ls -ld /shared-home
          echo "Creating temporary file in shared home as user $(id -u):$(id -g)"
          touch /shared-home/permissions-test
          ls -l /shared-home/permissions-test
          rm /shared-home/permissions-test
      {{- with .Values.testPods.resources }}
      resources:
      {{- toYaml . | nindent 8 }}
      {{- end }}
  volumes:
    {{ include "jira.volumes.sharedHome" . | nindent 4 }}
  restartPolicy: Never
  {{- with .Values.testPods.nodeSelector }}
  nodeSelector:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- with .Values.testPods.affinity }}
  affinity:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- with .Values.testPods.tolerations }}
  tolerations:
  {{- toYaml . | nindent 8 }}
  {{- end }}
  {{- if .Values.testPods.schedulerName }}
  schedulerName: {{ .Values.testPods.schedulerName  | quote }}
  {{- end }}
